(function(){
  const Ns = [5,7,8,12,15,16];
  const selN = $('#cy-N'), pin = $('#cy-p'), svg = $('#cy-svg'), out = $('#cy-out');
  Ns.forEach(n=>{ const o=document.createElement('option'); o.value=n; o.textContent=String(n); selN.appendChild(o); });
  selN.value = 12;
  function render(){
    const N = +selN.value;
    const pv = +pin.value;
    // elements of (Z/N)^*
    const elts = [];
    for(let k=1;k<N;k++){
      if(gcd(k,N)===1) elts.push(k);
    }
    // layout on a circle
    while(svg.firstChild) svg.removeChild(svg.firstChild);
    const cx=310, cy=130, R=95;
    // title
    const tH = SVG('text',{x:310, y:22, 'text-anchor':'middle', 'font-size':13, fill:'var(--mute)'});
    tH.textContent = `|(ℤ/${N})×| = ${elts.length},  Frob_p = p mod ${N}`;
    svg.appendChild(tH);
    const n = elts.length;
    let frobRes = null;
    if(isPrime(pv) && gcd(pv,N)===1) frobRes = mod(pv,N);
    for(let i=0;i<n;i++){
      const ang = -Math.PI/2 + 2*Math.PI*i/n;
      const x = cx + R*Math.cos(ang), y = cy + R*Math.sin(ang);
      const isFrob = elts[i] === frobRes;
      drawNode(svg, x, y, String(elts[i]), {r:18, stroke: isFrob?'var(--yellow)':'var(--blue)'});
    }
    // describe cycle structure of Frob_p acting on roots of unity — i.e. order of p in (Z/N)*
    if(frobRes !== null){
      let ord = 1, curr = frobRes;
      while(curr !== 1 && ord < N*2){ curr = mod(curr*frobRes, N); ord++; }
      const phiN = elts.length;
      const cycles = phiN / ord;
      out.textContent = `p = ${pv},  Frob_p = ${frobRes} mod ${N}.  order of Frob in G = ${ord}.\nΦ_${N}(x) mod ${pv} factors as ${cycles} irreducible piece(s), each of degree ${ord}.`;
    } else {
      if(!isPrime(pv)) out.textContent = `${pv} is not prime`;
      else out.textContent = `p = ${pv} divides N = ${N} (ramified).`;
    }
  }
  function gcd(a,b){ a=Math.abs(a); b=Math.abs(b); while(b){ [a,b]=[b,a%b]; } return a; }
  selN.addEventListener('change', render);
  pin.addEventListener('change', render);
  pin.addEventListener('keyup', e=>{ if(e.key==='Enter') render(); });
  render();
})();

